#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define fp float

#if defined(RD_WG_SIZE_0_0)
#define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define NUMBER_THREADS RD_WG_SIZE
#elif defined(BLOCK_SIZE)
#define NUMBER_THREADS BLOCK_SIZE
#else
#define NUMBER_THREADS 256
#endif

extern "C" {
void write_graphics(char* filename, fp* input, int data_rows, int data_cols, int major, int data_range);
void read_graphics(char* filename, fp* input, int data_rows, int data_cols, int major);
void resize(fp* input, int input_rows, int input_cols, fp* output, int output_rows, int output_cols, int major);

void kernel_gpu_opencl_wrapper(fp* image,
                               int Nr,
                               int Nc,
                               long Ne,
                               int niter,
                               fp lambda,
                               long NeROI,
                               int* iN,
                               int* iS,
                               int* jE,
                               int* jW,
                               int iter,
                               int mem_size_i,
                               int mem_size_j);
}

int platform_id_inuse = 0;
int device_id_inuse = 0;

int main(int argc, char* argv[]) {
    printf("WG size of kernel = %d \n", NUMBER_THREADS);

    fp* image_ori;
    int image_ori_rows;
    int image_ori_cols;
    long image_ori_elem;

    fp* image;
    int Nr, Nc;
    long Ne;

    int niter;
    fp lambda;

    int r1, r2, c1, c2;
    long NeROI;

    int* iN;
    int* iS;
    int* jE;
    int* jW;

    int iter;
    long i;
    long j;

    int mem_size_i;
    int mem_size_j;

    int cur_arg;
    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                niter = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
                lambda = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-s") == 0) {
            if (argc >= cur_arg + 3) {
                Nr = atoi(argv[cur_arg + 1]);
                Nc = atoi(argv[cur_arg + 2]);
                cur_arg += 2;
            }
        } else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
    }

    image_ori_rows = 502;
    image_ori_cols = 458;
    image_ori_elem = (long)image_ori_rows * image_ori_cols;

    image_ori = (fp*)malloc(sizeof(fp) * image_ori_elem);

    read_graphics("../../data/srad/image.pgm",
                  image_ori,
                  image_ori_rows,
                  image_ori_cols,
                  1);

    Ne = (long)Nr * Nc;

    image = (fp*)malloc(sizeof(fp) * Ne);

    resize(image_ori,
           image_ori_rows,
           image_ori_cols,
           image,
           Nr,
           Nc,
           1);

    r1 = 0;
    r2 = Nr - 1;
    c1 = 0;
    c2 = Nc - 1;

    NeROI = (long)(r2 - r1 + 1) * (c2 - c1 + 1);

    mem_size_i = sizeof(int) * Nr;
    iN = (int*)malloc(mem_size_i);
    iS = (int*)malloc(mem_size_i);
    mem_size_j = sizeof(int) * Nc;
    jW = (int*)malloc(mem_size_j);
    jE = (int*)malloc(mem_size_j);

    for (i = 0; i < Nr; i++) {
        iN[i] = (int)i - 1;
        iS[i] = (int)i + 1;
    }
    for (j = 0; j < Nc; j++) {
        jW[j] = (int)j - 1;
        jE[j] = (int)j + 1;
    }

    iN[0] = 0;
    iS[Nr - 1] = Nr - 1;
    jW[0] = 0;
    jE[Nc - 1] = Nc - 1;

    kernel_gpu_opencl_wrapper(image,
                              Nr,
                              Nc,
                              Ne,
                              niter,
                              lambda,
                              NeROI,
                              iN,
                              iS,
                              jE,
                              jW,
                              iter,
                              mem_size_i,
                              mem_size_j);

    write_graphics((char*)"./output/image_out.pgm",
                   image,
                   Nr,
                   Nc,
                   1,
                   255);

    free(image_ori);
    free(image);
    free(iN);
    free(iS);
    free(jW);
    free(jE);

    return 0;
}

